query:
mutation k8sCreateCluster($payload: K8sCreateClusterReq) {
  K8sCreateCluster(K8sCreateClusterReq: $payload) {
    cluster {
      uuid
      spec {
        name
        is_ha
        plugins {
          plugin {
            slug
            __typename
          }
          config
          __typename
        }
        __typename
      }
      worker_node_pools {
        uuid
        spec {
          auto_scale
          num_nodes
          min_nodes
          max_nodes
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
